import{_ as a,o,c as n,ag as t}from"./chunks/framework.CAXxHpAX.js";const i=JSON.parse('{"title":"甲午中日战争：1894-1895，侵略势","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-19.md","filePath":"notes/note-19.md"}'),r={name:"notes/note-19.md"};function e(s,p,l,c,d,b){return o(),n("div",null,[...p[0]||(p[0]=[t('<h1 id="甲午中日战争-1894-1895-侵略势" tabindex="-1">甲午中日战争：1894-1895，侵略势 <a class="header-anchor" href="#甲午中日战争-1894-1895-侵略势" aria-label="Permalink to &quot;甲午中日战争：1894-1895，侵略势&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">甲午中日战争：</span>1894-1895，侵略势力进一步深入中国腹地，大大加深了中国半殖民地化程度，刺激列强掀起瓜分中国狂潮，进一步加剧民族危机。激起中华民族觉醒，推动中国人民展开救亡图存斗争（百日维新、实业救国）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">《马关条约》：</span>割三地（辽东半岛、澎湖列岛、台湾）赔两亿（白银）开四口（沙市、重庆、苏州、杭州）允设厂（日本在通商口岸开设工厂）。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">《辛丑》：</span></p><p>①清政府赔款白银</p><p>4.5亿两，分39年还清，本息共计</p><ol start="9"><li>8亿两，以海关税、盐税等税收作担保;</li></ol><p>②清政府保证严禁人民参加各种形式的反帝活动;清政府拆毁大沽炮台，</p><p>③允许外国军队驻扎在从北京到山海关的铁路沿线要地;</p><p>④划定北京东交民巷为使馆界，允许各国派兵驻守，不准中国人居住，改总理衙门为外务部，班列六部之前。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">《辛丑》影响：</span>清政府沦为帝国主义列统治中国的工具，中国完全陷入半殖民地半封建社会的深渊。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、第一次近代化运动:</span>洋务运动（近代化的开端） 中国近代史的开端：鸦片战争</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、洋务运动破产的标志：</span>甲午战争北洋舰队全军覆没</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、拉开维新变法运动的序幕是：</span>公车上书</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、义和团的口号、性质：</span>扶清灭洋、广泛群众性反帝爱国运动</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、沦为洋人朝廷是哪个条约：</span>《辛丑条约》</p><p>6、客观上促进中国民族资本主义产生是哪件事？洋务运动</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、李鸿章办的军事工业：</span>江南机器制造总局（封建性质）</p><p>8、梁启超在（上海）办了《时务报》报刊。严复（天津）办了《国闻报》。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、政治近代化的开端是：</span>百日维新</p><p>1</p><p>0、沉重打击帝国主义瓜分中国野心是哪件事？义和团运动</p><p>1</p><p>1、教育近代化的开端是哪件事？洋务运动（京师同文馆）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、第一次鸦片战争的时间：</span>1840-1842年 导火线：林则徐虎门销烟</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、第二次鸦片战争的根本原因：</span>西方列强为打开中国市场，倾销商品，掠夺原材料</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、第一次鸦片战争失败根因：</span>清朝封建专制制度的腐败</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、近代侵占我国领土最多的国家是：</span>俄国</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、天平天国运动军事上全盛：</span>北伐、西征</p><p>8、西方侵略势力由东南沿海深入到长江中下游地区是哪场战争？第二次鸦片战争（《天津》外国商船和军舰可在长江各口岸自由航行。</p>',30)])])}const f=a(r,[["render",e]]);export{i as __pageData,f as default};
